const readResults = (nodeRef) => {
  try {
    const firstJson = nodeRef.first()?.json ?? null;

    if (Array.isArray(firstJson?.results)) {
      return firstJson.results;
    }

    return nodeRef
      .all()
      .map((item) => item.json)
      .filter((entry) => entry && typeof entry === 'object');
  } catch (error) {
    return [];
  }
};;

const base = $('Extract evidence window').first().json;
const fallbackResults = readResults($('Tavily Search'));
const extracts = readResults($('Tavily Extract'));
const candidate = base.deepCandidate ?? null;

const PRIORITY = {
  npm: 5,
  'migration-guide': 4,
  changelog: 4,
  'github-release': 4,
  'fallback-search': 3,
  docs: 2,
  repository: 1
};

const MAX_EXCERPT_LENGTH = {
  npm: 220,
  'migration-guide': 700,
  changelog: 700,
  'github-release': 700,
  'fallback-search': 320,
  docs: 280,
  repository: 240
};

function cleanText(value) {
  return String(value ?? '')
    .replace(/\r/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeLabel(value) {
  const label = cleanText(value);
  return label === 'repo' ? 'repository' : label;
}

function normalizeTitle(value, fallback) {
  const title = cleanText(value);
  return title || fallback || 'source';
}

function normalizeUrl(value) {
  return cleanText(value);
}

function buildCandidateMetadata(entry) {
  return {
    name: String(entry?.name ?? ''),
    currentVersion: String(entry?.currentVersion ?? ''),
    latestVersion: String(entry?.latestVersion ?? ''),
    group: String(entry?.group ?? ''),
    diffType: String(entry?.diffType ?? 'unknown'),
    deprecated: Boolean(entry?.deprecated),
    publishedAt: entry?.publishedAt ?? null,
    resolution: entry?.resolution ?? null
  };
}

function buildFallbackMetadata() {
  return {
    candidate: buildCandidateMetadata(candidate),
    evidenceStatus: 'none',
    evidence: []
  };
}

function summarizeRenovateDiff(excerpt) {
  const text = cleanText(excerpt);
  const fileMatches = [...text.matchAll(/\b([A-Za-z0-9._/-]+\.(?:d\.ts|ts|tsx|js|jsx|json|md))\b/g)];
  const files = [...new Set(fileMatches.map((match) => match[1]))].slice(0, 6);

  const hints = [];
  if (/index\.d\.ts/i.test(text)) hints.push('index.d.ts changed');
  if (/package\.json/i.test(text)) hints.push('package.json changed');
  if (/readme\.md/i.test(text)) hints.push('README.md changed');

  const parts = [];
  if (files.length) {
    parts.push(`Files changed: ${files.join(', ')}`);
  }
  if (hints.length) {
    parts.push(hints.join('; '));
  }

  return parts.join('. ') || text.slice(0, 320);
}

function isLowSignalEvidence(entry) {
  const excerpt = entry.excerpt.toLowerCase();
  const title = entry.title.toLowerCase();

  if (!excerpt) {
    return true;
  }

  if (
    entry.label === 'docs' &&
    (
      excerpt.includes('the repository for high quality typescript type definitions') ||
      excerpt.includes('you can also read this readme in') ||
      excerpt.includes('justification for new definitions') ||
      excerpt.includes('make-work prs') ||
      title === 'readme.md'
    )
  ) {
    return true;
  }

  if (
    entry.label === 'fallback-search' &&
    /terms of service|privacy policy|by logging in|big news!|gitlab|bitbucket|login\?/.test(excerpt)
  ) {
    return true;
  }

  return false;
}

function isVerifiedSource(entry) {
  if (entry.label === 'npm' && entry.title === 'deprecation notice') {
    return true;
  }

  if (!['github-release', 'changelog', 'migration-guide'].includes(entry.label)) {
    return false;
  }

  return entry.excerpt.length >= 80;
}

function normalizeEvidence(entry) {
  const label = normalizeLabel(entry.label);
  const url = normalizeUrl(entry.url);

  if (!label || !url) {
    return null;
  }

  let excerpt = cleanText(entry.excerpt);
  if (!excerpt) {
    return null;
  }

  if (label === 'fallback-search' && /app\.renovatebot\.com\/package-diff/i.test(url)) {
    excerpt = summarizeRenovateDiff(excerpt);
  }

  const normalized = {
    label,
    url,
    title: normalizeTitle(entry.title, label),
    excerpt: excerpt.slice(0, MAX_EXCERPT_LENGTH[label] ?? 400)
  };

  if (isLowSignalEvidence(normalized)) {
    return null;
  }

  return normalized;
}

if (!candidate) {
  const llmBriefInput = buildFallbackMetadata();

  return [
    {
      json: {
        ...base,
        evidence: [],
        evidenceStatus: 'none',
        llmBriefInput
      }
    }
  ];
}

const rawEvidence = [];
const seenRaw = new Set();

function pushRaw(entry) {
  const label = normalizeLabel(entry.label);
  const url = normalizeUrl(entry.url);

  if (!label || !url) {
    return;
  }

  const key = `${label}|${url}`;
  if (seenRaw.has(key)) {
    return;
  }

  seenRaw.add(key);
  rawEvidence.push({
    label,
    url,
    title: entry.title,
    excerpt: entry.excerpt
  });
}

for (const source of base.canonicalEvidence ?? []) {
  pushRaw(source);
}

for (const extract of extracts.slice(0, 2)) {
  const url = extract.url ?? extract.metadata?.url ?? null;

  pushRaw({
    label: 'fallback-search',
    url,
    title: extract.title ?? 'fallback source',
    excerpt: extract.raw_content ?? extract.content ?? ''
  });
}

for (const result of fallbackResults.slice(0, 2)) {
  pushRaw({
    label: 'fallback-search',
    url: result.url ?? null,
    title: result.title ?? 'fallback search result',
    excerpt: result.content ?? ''
  });
}

const evidence = rawEvidence
  .map(normalizeEvidence)
  .filter(Boolean)
  .sort((left, right) => {
    const byPriority = (PRIORITY[right.label] ?? 0) - (PRIORITY[left.label] ?? 0);
    if (byPriority !== 0) {
      return byPriority;
    }

    return left.url.localeCompare(right.url);
  })
  .slice(0, 4);

const evidenceStatus = evidence.some(isVerifiedSource)
  ? 'verified'
  : evidence.length
    ? 'partial'
    : 'none';

const llmBriefInput = {
  candidate: buildCandidateMetadata(candidate),
  evidenceStatus,
  evidence: evidence.map(({ label, url, title, excerpt }) => ({
    label,
    url,
    title,
    excerpt
  }))
};

return [
  {
    json: {
      ...base,
      evidence,
      evidenceStatus,
      llmBriefInput
    }
  }
];

const data = $input.first().json;
const candidate = data.deepCandidate ?? null;
const resolution = candidate?.resolution ?? {};
const repoUrl = candidate?.repositoryUrl ?? candidate?.sourceUrls?.find((url) => String(url).includes('github.com')) ?? null;
const match = typeof repoUrl === 'string' ? repoUrl.match(/github\.com\/([^/]+)\/([^/#?]+)/i) : null;
const repoSlug = match ? (match[1] + '/' + match[2]).replace(/\.git$/i, '') : null;
const github = repoSlug ? { owner: repoSlug.split('/')[0], repo: repoSlug.split('/')[1], repoSlug } : null;
const cleanVersion = (value) => {
  if (!value) return null;
  const versionMatch = String(value).match(/(\d+\.\d+\.\d+(?:[-+][0-9A-Za-z.-]+)?)/);
  return versionMatch ? versionMatch[1] : null;
};
const registryPackageName = resolution.registryPackageName ?? candidate?.name ?? null;
return [{ json: { ...data, deepCandidate: candidate, repoUrl, github, npmUrl: registryPackageName ? ('https://www.npmjs.com/package/' + registryPackageName) : null, currentVersionClean: candidate ? cleanVersion(resolution.wantedVersion ?? candidate.currentVersion) : null, latestVersionClean: candidate ? cleanVersion(resolution.latestVersion ?? candidate.latestVersion) : null, skipResearch: Boolean(data.skipResearch || !candidate) } }];

const context = $('Normalize package context').first().json;

const contents = $input
  .all()
  .map(({ json }) => ({
    name: json.name ?? json.fileName ?? '',
    path: json.path ?? json.filePath ?? '',
    url: json.url ?? json.self ?? null,
    download_url: json.download_url ?? json.downloadUrl ?? null,
    html_url: json.html_url ?? json.htmlUrl ?? null,
    type: json.type ?? null,
  }))
  .filter((entry) => entry.name && entry.path);

const classify = (entry) => {
  const fileName = String(entry.name ?? '').toLowerCase();
  if (!fileName || entry.type === 'dir') return null;

  if (fileName.includes('migration') || fileName.includes('upgrade')) {
    return {
      name: entry.name,
      path: entry.path,
      apiUrl: entry.url,
      downloadUrl: entry.download_url ?? null,
      htmlUrl: entry.html_url ?? entry.download_url ?? context.repoUrl,
      label: 'migration-guide',
      priority: 1,
    };
  }

  if (
    fileName.includes('changelog') ||
    fileName === 'changes.md' ||
    fileName === 'history.md' ||
    fileName.includes('release-notes')
  ) {
    return {
      name: entry.name,
      path: entry.path,
      apiUrl: entry.url,
      downloadUrl: entry.download_url ?? null,
      htmlUrl: entry.html_url ?? entry.download_url ?? context.repoUrl,
      label: 'changelog',
      priority: 2,
    };
  }

  if (fileName === 'readme.md' || fileName === 'readme') {
    return {
      name: entry.name,
      path: entry.path,
      apiUrl: entry.url,
      downloadUrl: entry.download_url ?? null,
      htmlUrl: entry.html_url ?? entry.download_url ?? context.repoUrl,
      label: 'docs',
      priority: 3,
    };
  }

  return null;
};

const docCandidates = contents
  .map(classify)
  .filter(Boolean)
  .sort((left, right) => left.priority - right.priority || left.name.localeCompare(right.name));

return [{
  json: {
    ...context,
    docCandidates: docCandidates.slice(0, 3),
    primaryDocTarget: docCandidates[0] ?? null,
  }
}];

const context = $('Normalize package context').first().json;
const npm = $('npm registry metadata').first()?.json ?? {};
return [{
  json: {
    context,
    npm,
    releases: [],
    primaryDocTarget: null,
    docPayload: null
  }
}];

const context = $('Normalize package context').first().json;
const npm = $('npm registry metadata').first()?.json ?? {};
const docSelection = $('Select documentation target').first()?.json ?? {};
const releases = $input.all().map((item) => item.json).filter((entry) => entry && typeof entry === 'object');
let docPayload = null;
try {
  docPayload = $('GitHub documentation raw').first()?.json ?? null;
} catch (error) {
  docPayload = null;
}
return [{
  json: {
    context,
    npm,
    releases,
    primaryDocTarget: docSelection.primaryDocTarget ?? null,
    docPayload
  }
}];

const envelope = $input.first().json ?? {};
const context = envelope.context ?? {};
const npm = envelope.npm ?? {};
const releases = Array.isArray(envelope.releases) ? envelope.releases : [];
const primaryDocTarget = envelope.primaryDocTarget ?? null;
const docPayload = envelope.docPayload ?? null;
const candidate = context.deepCandidate ?? null;

const normalizeText = (value) => {
  if (typeof value === 'string') return value;
  if (value === null || value === undefined) return '';
  if (Array.isArray(value)) {
    return value.map(normalizeText).filter(Boolean).join('\n\n');
  }
  if (typeof value === 'object') {
    for (const key of ['content', 'text', 'body', 'data', 'raw', 'readme']) {
      if (typeof value[key] === 'string') return value[key];
    }
    return '';
  }
  return String(value);
};

if (context.skipResearch || !candidate) {
  return [{
    json: {
      ...context,
      canonicalEvidence: [],
      canonicalEvidenceStatus: 'none',
      needsFallback: true,
    }
  }];
}

const cleanVersion = (value) => {
  if (!value) return null;
  const versionMatch = String(value).match(/(\d+\.\d+\.\d+(?:[-+][0-9A-Za-z.-]+)?)/);
  return versionMatch ? versionMatch[1] : null;
};

const parseSemver = (value) => {
  const cleaned = cleanVersion(value);
  if (!cleaned) return null;
  const match = cleaned.match(/^(\d+)\.(\d+)\.(\d+)/);
  if (!match) return null;
  return {
    raw: cleaned,
    major: Number(match[1]),
    minor: Number(match[2]),
    patch: Number(match[3]),
  };
};

const compareSemver = (left, right) => {
  if (!left || !right) return 0;
  if (left.major !== right.major) return left.major - right.major;
  if (left.minor !== right.minor) return left.minor - right.minor;
  return left.patch - right.patch;
};

const pickDocExcerpt = (text, versions) => {
  const source = normalizeText(text).replace(/\r/g, '');
  if (!source.trim()) return '';

  const needles = versions
    .filter(Boolean)
    .flatMap((value) => [value, `v${value}`, `[${value}]`])
    .map((value) => String(value).toLowerCase());

  const haystack = source.toLowerCase();
  let index = -1;

  for (const needle of needles) {
    const found = haystack.indexOf(needle);
    if (found >= 0) {
      index = found;
      break;
    }
  }

  if (index < 0) return source.slice(0, 1400);

  const start = Math.max(0, index - 220);
  return source.slice(start, start + 1400);
};

const decodeDocContent = (payload) => {
  if (!payload) return '';
  if (typeof payload === 'string') return payload;

  for (const key of ['content', 'data', 'fileContent', 'text', 'body']) {
    if (typeof payload[key] === 'string') {
      if (payload.encoding === 'base64') {
        try {
          return Buffer.from(payload[key].replace(/\n/g, ''), 'base64').toString('utf8');
        } catch (error) {
          return '';
        }
      }
      return payload[key];
    }
  }

  return '';
};

const currentPublishedAt =
  context.currentVersionClean && npm?.time?.[context.currentVersionClean]
    ? npm.time[context.currentVersionClean]
    : null;

const latestPublishedAt =
  context.latestVersionClean && npm?.time?.[context.latestVersionClean]
    ? npm.time[context.latestVersionClean]
    : null;

const metadataBits = [
  `Current ${candidate.currentVersion}`,
  `latest ${candidate.latestVersion}`,
  `diff ${candidate.diffType}`,
  `deprecated ${candidate.deprecated}`,
  currentPublishedAt ? `current published ${currentPublishedAt}` : null,
  latestPublishedAt ? `latest published ${latestPublishedAt}` : null,
  npm?.['dist-tags']?.latest ? `dist-tag latest ${npm['dist-tags'].latest}` : null,
].filter(Boolean).join('; ');

const evidence = [{
  packageName: candidate.name,
  label: 'npm',
  url: context.npmUrl,
  title: 'npm metadata',
  excerpt: metadataBits,
  confidence: 'high',
}];

let deprecatedMessage = null;
for (const key of [
  context.latestVersionClean,
  candidate.latestVersion,
  context.currentVersionClean,
  candidate.currentVersion,
]) {
  if (key && npm?.versions?.[key]?.deprecated) {
    deprecatedMessage = npm.versions[key].deprecated;
    break;
  }
}

if (deprecatedMessage || candidate.deprecated) {
  evidence.push({
    packageName: candidate.name,
    label: 'npm',
    url: context.npmUrl,
    title: 'deprecation notice',
    excerpt: String(
      deprecatedMessage ?? 'npm y el analisis base marcan este paquete como deprecated.'
    ),
    confidence: 'high',
  });
}

const currentParsed = parseSemver(context.currentVersionClean ?? candidate.currentVersion);
const latestParsed = parseSemver(context.latestVersionClean ?? candidate.latestVersion);
const releaseList = releases.filter((release) => release && typeof release === 'object');
const relevantReleases = releaseList.filter((release) => {
  const parsed = parseSemver(String(release?.tag_name ?? release?.name ?? ''));
  if (!parsed) return false;
  if (latestParsed && compareSemver(parsed, latestParsed) > 0) return false;
  if (currentParsed && compareSemver(parsed, currentParsed) <= 0) return false;
  return true;
});

const selectedReleases = (relevantReleases.length ? relevantReleases : releaseList).slice(0, 4);

for (const release of selectedReleases) {
  const body = normalizeText(release?.body).trim();
  if (body.length < 40) continue;

  evidence.push({
    packageName: candidate.name,
    label: 'github-release',
    url: release.html_url ?? context.repoUrl ?? context.npmUrl,
    title: release.name ?? release.tag_name ?? 'release',
    excerpt: body.slice(0, 1400),
    publishedAt: release.published_at ?? null,
    confidence: 'high',
  });
}

const docContent = decodeDocContent(docPayload);

if (primaryDocTarget && docContent.trim()) {
  evidence.push({
    packageName: candidate.name,
    label: primaryDocTarget.label,
    url: primaryDocTarget.htmlUrl ?? primaryDocTarget.downloadUrl ?? context.repoUrl ?? context.npmUrl,
    title: primaryDocTarget.name,
    excerpt: pickDocExcerpt(docContent, [context.latestVersionClean, context.currentVersionClean]),
    confidence: primaryDocTarget.label === 'docs' ? 'medium' : 'high',
  });
} else {
  const npmReadme = normalizeText(npm?.readme);
  if (!selectedReleases.length && npmReadme.trim()) {
    evidence.push({
      packageName: candidate.name,
      label: 'docs',
      url: context.npmUrl,
      title: 'README from npm registry',
      excerpt: pickDocExcerpt(npmReadme, [context.latestVersionClean, context.currentVersionClean]),
      confidence: 'medium',
    });
  }
}

const verifiedCanonicalEvidence = evidence.filter((entry) => {
  if (entry.label === 'npm' && entry.title === 'deprecation notice') return true;
  if (!['github-release', 'changelog', 'migration-guide'].includes(entry.label)) return false;
  return String(entry.excerpt ?? '').trim().length >= 80;
});

const canonicalEvidenceStatus =
  verifiedCanonicalEvidence.length ? 'verified' : evidence.length ? 'partial' : 'none';

return [{
  json: {
    ...context,
    canonicalEvidence: evidence.slice(0, 8),
    canonicalEvidenceStatus,
    needsFallback: verifiedCanonicalEvidence.length === 0,
    primaryDocTarget,
  }
}];

const raw = $input.first().json;
const parsed = raw.output ?? raw;

const prep = $('Prepare package brief input').first().json;
const candidate = prep.deepCandidate;
const resolution = candidate?.resolution ?? {};
const declaredSpec = resolution.declaredSpec ?? candidate.currentVersion;
const wantedVersion = resolution.wantedVersion ?? candidate.currentVersion;
const latestVersion = resolution.latestVersion ?? candidate.latestVersion;
const requiresManualReview = Boolean(resolution.requiresManualReview);

const fallbackBrief = {
  name: candidate.name,
  summary:
    prep.evidenceStatus === 'verified'
      ? `Spec ${declaredSpec}. Wanted ${wantedVersion}; latest ${latestVersion}. Evidencia verificada disponible para revisar antes del merge.`
      : prep.evidenceStatus === 'partial'
        ? `Spec ${declaredSpec}. Wanted ${wantedVersion}; latest ${latestVersion}. Evidencia parcial; revisa fuentes oficiales antes de aplicar cambios sensibles.`
        : `Spec ${declaredSpec}. Wanted ${wantedVersion}; latest ${latestVersion}. No hubo evidencia suficiente para afirmar breaking changes verificables.`,
  breakingChanges: [],
  testFocus: candidate.deprecated
    ? [
        'Validar rutas criticas que aun usan el paquete deprecated',
        'Aislar impacto de la sustitucion o remocion'
      ]
    : requiresManualReview
      ? [
          'Verificar cómo se resuelve realmente el spec en instalación o lockfile',
          'Confirmar compatibilidad manual antes de cambiar canal, alias o fuente'
        ]
      : [
          'Smoke test del flujo principal afectado',
          'Verificar build, imports y arranque del proyecto'
        ],
  riskLevel:
    candidate.deprecated || candidate.diffType === 'major' || requiresManualReview
      ? 'high'
      : candidate.diffType === 'minor'
        ? 'medium'
        : 'low',
  confidence:
    prep.evidenceStatus === 'verified'
      ? 'high'
      : prep.evidenceStatus === 'partial'
        ? 'medium'
        : 'low',
  evidenceStatus: prep.evidenceStatus ?? 'none',
  recommendedActions: candidate.deprecated
    ? [
        'Planificar reemplazo o salida gradual',
        'No expandir nuevas dependencias sobre este paquete'
      ]
    : requiresManualReview
      ? [
          'Tratar este paquete como manual review antes de proponer un upgrade automático',
          'Revisar declaredSpec, wantedVersion y latestVersion antes de cambiar el comportamiento actual'
        ]
      : [
          'Aplicar upgrade en rama corta',
          'Validar test focus antes de mergear'
        ],
  sources: []
};

const allowedSources = new Map();
for (const entry of prep.evidence ?? []) {
  const url = String(entry?.url ?? '');
  const label = String(entry?.label ?? '');
  if (!url || !label) continue;
  if (!allowedSources.has(url)) {
    allowedSources.set(url, {
      packageName: candidate.name,
      label,
      url
    });
  }
}

const merged = { ...fallbackBrief, ...parsed };

const sources = [];
const seen = new Set();

for (const source of [
  ...((merged.sources ?? []).filter(Boolean)),
  ...((prep.evidence ?? []).map((entry) => ({
    packageName: candidate.name,
    label: entry.label,
    url: entry.url
  })))
]) {
  const url = String(source?.url ?? '');
  const canonical = allowedSources.get(url);
  if (!canonical) continue;

  const key = `${canonical.packageName}|${canonical.label}|${canonical.url}`;
  if (seen.has(key)) continue;

  seen.add(key);
  sources.push(canonical);
}

return [
  {
    json: {
      packageBrief: {
        ...merged,
        name: candidate.name,
        sources
      }
    }
  }
];
